INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0155488a-8916-4afa-8768-6e5a72a9da88',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Code Splitting — Manual Chunks, Dynamic Imports, and Route-Based Splitting$escape$,
  $escape$Vite's Rollup-based build splits code automatically, but you control the strategy. Dynamic imports create split points instantly — Vite emits a separate chunk per `import()` call with zero config. For route-based splitting in React, wrap lazy-loaded components with `React.lazy` and `Suspense`; Vite handles the chunk boundaries automatically.

For finer control, use `build.rollupOptions.output.manualChunks` in `vite.config.ts`. This lets you group vendor libraries into a stable `vendor` chunk, preventing cache-busting on every app change. You can pass a function instead of an object for dynamic logic — inspect the module ID and return a chunk name.

Avoid over-splitting: too many small chunks increases waterfall requests. Vite's `build.chunkSizeWarningLimit` (default 500 kB) flags bloated chunks. Use `vite-bundle-visualizer` or `rollup-plugin-visualizer` to audit your output. For async routes that share heavy deps like `lodash`, pin them to `manualChunks` so they're fetched once and cached across routes.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  build: {
    rollupOptions: {
      output: {
        manualChunks(id) {
          if (id.includes('node_modules')) {
            if (id.includes('react') || id.includes('react-dom')) return 'react-vendor';
            if (id.includes('lodash')) return 'utils-vendor';
            return 'vendor';
          }
        },
      },
    },
  },
});

// Route-level split in app code
const Dashboard = React.lazy(() => import('./pages/Dashboard'));$escape$,
  $escape$typescript$escape$,
