INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b41ba122-346a-4474-864b-96b6e396adb2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Tree Shaking — How Side Effects Break It and How to Fix Them$escape$,
  $escape$Vite delegates tree shaking to Rollup during `vite build`. Rollup statically analyzes ES module imports and eliminates exports that are never referenced — but only when it can prove a module is side-effect-free. If a package's `package.json` omits `"sideEffects": false`, Rollup conservatively keeps every imported module in the bundle, even if you only use one named export.

This matters most with utility libraries. Importing `import { merge } from 'lodash-es'` is safe — lodash-es ships proper ESM with `"sideEffects": false`. But a library that mutates globals or registers polyfills on import cannot be marked pure.

For your own packages consumed by Vite, set `"sideEffects": false` in `package.json`, or list specific files that do have side effects: `"sideEffects": ["./src/polyfills.js"]`. Inside `vite.config.ts`, you can also pass Rollup's `treeshake` option for fine-grained control — for example, `treeshake: { moduleSideEffects: false }` tells Rollup to assume all modules are pure unless proven otherwise. Verify results with `vite build --reporter verbose` or inspect the Rollup bundle visualizer plugin.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite'
import { visualizer } from 'rollup-plugin-visualizer'

export default defineConfig({
  build: {
    rollupOptions: {
      treeshake: {
        // Assume no modules have side effects unless package.json says otherwise
        moduleSideEffects: false,
        propertyReadSideEffects: false,
      },
    },
  },
  plugins: [
    visualizer({ open: true, gzipSize: true }), // inspect what survived tree shaking
  ],
})$escape$,
  $escape$typescript$escape$,
