INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '05bf23e2-3496-4275-9b5a-ed782dc9ff5f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Bundle Analysis — Visualizing Size, Finding Bloat, and Setting CI Budgets$escape$,
  $escape$Vite's rollup-based output gives you full control over bundle introspection. Install `rollup-plugin-visualizer` and add it to your `vite.config.ts` plugins array — on build it generates an interactive treemap (`stats.html`) showing every module's contribution to your chunks. Spot bloat fast: a lodash import pulling in 70 KB signals you need `lodash-es` with tree-shaking, or a targeted `lodash.debounce` import instead.

For CI enforcement, Vite exposes `build.chunkSizeWarningLimit` (default 500 KB), but that's just a warning. Real enforcement comes via `vite-bundle-analyzer` or a custom Rollup plugin using the `generateBundle` hook — iterate `bundle` entries, sum `.code.length`, and `throw` if a chunk exceeds your budget. Pair this with `build.rollupOptions.output.manualChunks` to split vendor libraries into predictable named chunks (`vendor-react`, `vendor-charts`) so regressions are immediately obvious in diffs. Run `vite build --mode production` in CI and fail the pipeline on oversized output.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite';
import { visualizer } from 'rollup-plugin-visualizer';

export default defineConfig({
  build: {
    chunkSizeWarningLimit: 400,
    rollupOptions: {
      output: {
        manualChunks: {
          'vendor-react': ['react', 'react-dom'],
          'vendor-charts': ['recharts'],
        },
      },
      plugins: [
        {
          name: 'enforce-budget',
          generateBundle(_, bundle) {
            for (const [name, chunk] of Object.entries(bundle)) {
              if (chunk.type === 'chunk' && chunk.code.length > 400_000) {
                throw new Error(`Chunk "${name}" exceeds 400 KB budget`);
              }
            }
          },
        },
      ],
    },
  },
  plugins: [visualizer({ open: false, filename: 'dist/stats.html' })],
});$escape$,
  $escape$typescript$escape$,
