INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ae6d3ed0-134d-41db-abce-7400f29262a6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Asset Handling — Hashing, Inlining, and Cache Busting Done Right$escape$,
  $escape$Vite processes static assets through its asset pipeline, applying content-based hashing to filenames in production builds — `logo.png` becomes `logo.Bx3kW9aP.png`. This hash changes only when file content changes, giving you aggressive CDN caching with automatic invalidation.

Import assets directly in JS/TS to get the resolved, hashed URL at runtime:

```ts
import logoUrl from './assets/logo.png'
```

Files under 4KB are inlined as base64 data URIs by default, eliminating a network round-trip. Control this threshold via `build.assetsInlineLimit` in `vite.config.ts`.

For SVGs, Vite treats them as URLs by default, but with `vite-plugin-svgr` you can import them as React components. Fonts placed in `public/` skip the pipeline entirely — no hashing, no transform — ideal when you need stable URLs for `@font-face` declarations.

The `public/` directory is your escape hatch: files here are copied as-is and referenced with absolute paths like `/favicon.ico`. Everything else goes through the pipeline and gets a content hash.

Customize the output filename pattern with `build.rollupOptions.output.assetFileNames`: `'assets/[name].[hash][extname]'`.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite'

export default defineConfig({
  build: {
    assetsInlineLimit: 8192, // inline files < 8KB as base64
    rollupOptions: {
      output: {
        assetFileNames: 'assets/[name].[hash][extname]',
        chunkFileNames: 'chunks/[name].[hash].js',
      },
    },
  },
})

// In a component:
import heroUrl from './assets/hero.webp'
import fontUrl from './assets/Inter.woff2'
// heroUrl → '/assets/hero.Bx3kW9aP.webp' in prod$escape$,
  $escape$typescript$escape$,
