INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a42e9fcf-9a05-414e-bbc3-b471700271ac',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Environment Variables — .env Files, Build-Time Injection, and the define Plugin$escape$,
  $escape$Vite exposes env variables to client code only if they're prefixed with VITE_. Files like .env, .env.local, .env.production are loaded automatically via dotenv — but only VITE_* keys land in import.meta.env. Non-prefixed keys stay server-side only.

At build time, Vite statically replaces import.meta.env.VITE_API_URL with its literal string value. This means dead-code elimination works: if (import.meta.env.DEV) branches get stripped in production builds. import.meta.env.MODE, .DEV, .PROD, and .SSR are always available.

For values that can't be known at build time — think feature flags fetched from a config server — use the define plugin option in vite.config.ts. define performs a direct AST-level string replacement, so __APP_VERSION__ becomes '1.2.3' in the output bundle without any runtime lookup.

Critical distinction: import.meta.env values are frozen at build time. If you need true runtime config (e.g. per-deployment API URLs without rebuilding), serve a /config.json and fetch it at app startup instead.$escape$,
  $escape$// vite.config.ts
import { defineConfig, loadEnv } from 'vite'

export default defineConfig(({ mode }) => {
  const env = loadEnv(mode, process.cwd(), '') // loads ALL keys, not just VITE_

  return {
    define: {
      __APP_VERSION__: JSON.stringify(process.env.npm_package_version),
      __BUILD_TIME__: JSON.stringify(new Date().toISOString()),
    },
    // Access non-VITE_ keys server-side only:
    server: {
      proxy: {
        '/api': env.INTERNAL_API_URL, // never exposed to client bundle
      },
    },
  }
})$escape$,
  $escape$typescript$escape$,
