INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8722acc9-fa79-46b4-aab6-6059e886309b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Source Maps — Types and Production Trade-offs$escape$,
  $escape$Vite exposes `build.sourcemap` with four modes that behave very differently in production. `true` emits separate `.map` files alongside your chunks — Rollup writes them, browsers load them on-demand, and your bundle size stays lean. `'inline'` base64-encodes the entire map into each chunk, bloating output by 2–3× — never ship this to prod. `'hidden'` generates `.map` files but strips the `//# sourceMappingURL` comment, so browsers ignore them while tools like Sentry can still upload and symbolicate crash reports via `sentry-vite-plugin`. The default is `false`, meaning zero map output.

For most production setups, `'hidden'` is the right call: you get full stack trace symbolication in your error monitoring tool without leaking original source to end users. Pair it with `sentry-vite-plugin`'s `sourcemaps.filesToDeleteAfterUpload` to scrub `.map` files from your deploy artifact post-upload. For internal tools or staging, `true` is fine — just ensure your CDN or server blocks `.map` requests if source privacy matters.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite'
import { sentryVitePlugin } from '@sentry/vite-plugin'

export default defineConfig({
  build: {
    sourcemap: 'hidden', // emits .map files, no sourceMappingURL comment
  },
  plugins: [
    sentryVitePlugin({
      org: 'your-org',
      project: 'your-project',
      sourcemaps: {
        filesToDeleteAfterUpload: ['./dist/**/*.map'],
      },
    }),
  ],
})$escape$,
  $escape$typescript$escape$,
