INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6e46177c-0966-41bc-9c61-50cec1a9ada9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite CSS Processing — PostCSS, CSS Modules, and Preprocessors Without Extra Config$escape$,
  $escape$Vite has first-class CSS processing built into its transform pipeline — no webpack loaders, no manual plugin wiring. PostCSS runs automatically if a `postcss.config.js` (or `.cjs`) exists at the root; Vite picks it up and applies it to every CSS file it processes, including those inside `<style>` blocks in `.vue` files.

CSS Modules work out of the box for any file named `*.module.css`. Import it as a JS object and Vite generates scoped class names at build time. The `modules` option in `vite.config.ts` under `css.modules` lets you configure `localsConvention`, `generateScopedName`, and more.

For preprocessors — Sass, Less, Stylus — install the preprocessor itself (`npm i -D sass`) and Vite's resolver handles the rest. No `vite-plugin-sass` needed. You can pass preprocessor options globally via `css.preprocessorOptions.scss.additionalData` to inject shared variables into every file without explicit imports.

LightningCSS is available as an opt-in replacement for both esbuild's CSS minifier and PostCSS, enabled via `css.transformer: 'lightningcss'` in Vite 4.4+.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite'

export default defineConfig({
  css: {
    modules: {
      localsConvention: 'camelCaseOnly',
    },
    preprocessorOptions: {
      scss: {
        additionalData: `@use "@/styles/tokens" as *;`,
      },
    },
    // Opt into LightningCSS (Vite 4.4+)
    transformer: 'lightningcss',
  },
})$escape$,
  $escape$typescript$escape$,
