INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b5674233-4d05-4ba4-9622-16ff3af5ef66',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Monorepos — Workspace Packages, Shared Configs, and Turborepo$escape$,
  $escape$Vite plays well in monorepos when you wire it correctly. Use `resolve.alias` or `optimizeDeps.include` to ensure workspace packages are processed by Vite's pipeline rather than served as pre-bundled CJS artifacts. In a pnpm/npm workspace, sibling packages linked via `workspace:*` are treated as source — not node_modules — so Vite won't pre-bundle them unless you explicitly add them to `optimizeDeps.include`.

For shared Vite configs, export a base config factory from a `@repo/vite-config` package and merge it per-app using `mergeConfig` from `vite`. This keeps plugin arrays, resolve aliases, and test settings DRY across apps.

With Turborepo, define a `build` pipeline that caches `.vite` and `dist` outputs. Set `inputs` to include your shared config package so cache invalidation propagates correctly — a change in `@repo/vite-config` should bust all downstream app builds. Pair this with Vite's `build.watch` mode during local dev for incremental rebuilds across packages without restarting HMR servers.$escape$,
  $escape$// packages/vite-config/index.ts
import { defineConfig, mergeConfig, type UserConfig } from 'vite';

export function baseConfig(overrides: UserConfig = {}) {
  return mergeConfig(
    defineConfig({
      resolve: { alias: { '@repo/ui': '/packages/ui/src' } },
      optimizeDeps: { include: ['@repo/utils'] },
    }),
    overrides
  );
}

// apps/web/vite.config.ts
import { baseConfig } from '@repo/vite-config';
import react from '@vitejs/plugin-react';

export default baseConfig({ plugins: [react()] });$escape$,
  $escape$typescript$escape$,
