INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '01211b23-e6f1-4cad-982e-f7e16a298415',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vite Build Monitoring — Track Build Times and Catch Bundle Regressions in CI$escape$,
  $escape$Vite exposes build metadata you can hook into for CI-level monitoring. The `vite-bundle-analyzer` plugin generates stats, but for lightweight regression alerts, lean on Vite's built-in `rollupOptions` and the `generateBundle` hook directly.

Use a custom Vite plugin that records chunk sizes post-build and compares them against a committed baseline (`bundle-baseline.json`). In CI, fail the job if any chunk exceeds its baseline by more than a configurable threshold (e.g. 10%).

For build time tracking, wrap `vite build` with `perf_hooks` or simply use `time` in CI and pipe results to a metrics store. Vite 5+ also emits `vite:buildStart` and `vite:buildEnd` events you can tap via plugin hooks.

Store baselines in version control so every PR diff shows bundle impact. Pair with GitHub Actions' `actions/upload-artifact` to persist `stats.json` across runs for trend analysis. This gives you bundle size history without a paid service.$escape$,
  $escape$// vite.config.ts
import { defineConfig, Plugin } from 'vite';
import { readFileSync, writeFileSync, existsSync } from 'fs';

function bundleGuardPlugin(thresholdPct = 10): Plugin {
  return {
    name: 'bundle-guard',
    generateBundle(_, bundle) {
      const baseline = existsSync('bundle-baseline.json')
        ? JSON.parse(readFileSync('bundle-baseline.json', 'utf-8'))
        : {};
      const current: Record<string, number> = {};
      for (const [name, chunk] of Object.entries(bundle)) {
        if (chunk.type === 'chunk') {
          current[name] = Buffer.byteLength(chunk.code, 'utf-8');
          const base = baseline[name];
          if (base && current[name] > base * (1 + thresholdPct / 100)) {
            throw new Error(`Bundle regression: ${name} grew ${((current[name] / base - 1) * 100).toFixed(1)}%`);
          }
        }
      }
      writeFileSync('bundle-baseline.json', JSON.stringify(current, null, 2));
    },
  };
}

export default defineConfig({ plugins: [bundleGuardPlugin(10)] });$escape$,
  $escape$typescript$escape$,
